import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { featureInvariantCapRule } from "./feature-invariant-cap.rule.js";

// Names use a letter prefix + number so the numeric-suffix rule doesn't fire.
// E.g. inv_a_01 has 3 tokens — valid shape.
const INV_NAMES = [
  "inv_a_one", "inv_b_two", "inv_c_three", "inv_d_four", "inv_e_five",
  "inv_f_six", "inv_g_seven", "inv_h_eight", "inv_i_nine", "inv_j_ten",
  "has_field_one", "has_field_two", "has_field_three", "has_field_four",
  "has_field_five", "has_field_six", "has_field_seven", "has_field_eight",
  "has_field_nine", "has_field_ten", "entity_has_id",
];

/** Generates N @invariant ops inside the feature namespace. */
function makeInvariants(count: number): string {
  const ops: string[] = [];
  for (let i = 0; i < count; i++) {
    ops.push(
      `@invariant(#{ predicate: "true", why: "reason" }) op ${INV_NAMES[i]}(): void;`,
    );
  }
  return ops.join("\n          ");
}

describe("feature-invariant-cap rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(
      runner,
      featureInvariantCapRule,
      "@a10n/blueprint-typespec",
    );
  });

  // ─── valid ────────────────────────────────────────────────────────────────

  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T002.T002_01
    it("feature with 0 invariants passes", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T002.T002_02
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_feature_invariant_cap:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.feature_invariant_cap:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_inline_refs:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.feature_invariant_cap:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_feature_invariant_cap
    it("feature with exactly 20 invariants passes", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {
            ${makeInvariants(20)}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T002.T002_03
    it("namespace without @feature is ignored even with many ops", async () => {
      await ruleTester
        .expect(`
          namespace SomeOtherNs {
            op op_01(): void;
            op op_02(): void;
          }
        `)
        .toBeValid();
    });
  });

  // ─── invalid ──────────────────────────────────────────────────────────────

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T002.T002_04
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_feature_invariant_cap:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.feature_invariant_cap:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_feature_invariant_cap
    it("feature with 21 invariants emits warning", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {
            ${makeInvariants(21)}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/feature-invariant-cap",
          message: /21 invariants/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T002.T002_05
    it("message includes the feature FQN", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {
            ${makeInvariants(21)}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/feature-invariant-cap",
          message: /Products\.MyProduct\.Features\.MyFeature/,
        });
    });
  });
});
